#!/usr/bin/env bash
set -euo pipefail
ROOT="${1:-$PWD}"
if [[ ! -f "$ROOT/pyproject.toml" || ! -d "$ROOT/src/grid_world" ]]; then
  echo "ERROR: $ROOT is not a grid-world repository." >&2
  exit 1
fi
TMP="$(mktemp -d)"
base64 -d > "$TMP/patch.zip" <<'GRID_WORLD_DIVERSE_PATCH'

GRID_WORLD_DIVERSE_PATCH
unzip -qo "$TMP/patch.zip" -d "$ROOT"
rm -rf "$TMP"
cd "$ROOT"
python apply_diverse_patch.py
rm -f apply_diverse_patch.py
python -m compileall -q src
PYTHONPATH="$ROOT/src${PYTHONPATH:+:$PYTHONPATH}" python -m pytest -q tests/test_diverse_maps.py tests/test_grid.py tests/test_parser.py tests/test_targets.py
echo "Diverse 5x5 upgrade installed successfully."
echo "Next: grid-world maps generate --config configs/maps/grid5x5_diverse_1000.yaml --output data/generated/grid5x5_diverse_1000.jsonl"
